// WF6 NachfÃ¼llung: Verarbeite Webhook-Parameter und bereite Updates vor.
// Input: Query-Parameter aus dem Webhook (product_key, qty, notes)
const wh = $('Webhook').first()?.json?.query || {};
const productKey = String(wh.product_key || '').trim();
const notesIn    = String(wh.notes || '').trim();
const qtyIn      = wh.qty !== undefined ? Number(wh.qty) : null;

if (!productKey) {
  throw new Error('Fehlender Parameter: product_key ist Pflicht.');
}

function clean(v) { return String(v ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim(); }
function isActive(v) {
  return ['TRUE','1','JA','YES','AKTIV','ACTIVE'].includes(clean(v).toUpperCase());
}
function num(v) {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

// Produkte-Zeilen fÃ¼r diesen product_key
const allProdukte   = $('Google Sheets - Produkte lesen').all().map(i => i.json);
const allHinweise   = $('Google Sheets - Hinweise lesen').all().map(i => i.json);
const matchedSlots  = allProdukte.filter(p =>
  clean(p.product_key) === productKey && isActive(p.active)
);

if (!matchedSlots.length) {
  throw new Error('Kein aktiver Slot fÃ¼r product_key: ' + productKey);
}

const now = new Date().toISOString();
const productName = clean(
  matchedSlots[0].internal_product_name ||
  matchedSlots[0].nayax_product_name ||
  productKey
);

// Slot-Updates bauen
const slotUpdates = matchedSlots.map(p => {
  const capacity = num(p.machine_capacity) || 0;
  const newQty = qtyIn !== null ? Math.min(qtyIn, capacity) : capacity;
  return {
    product_slot_id: clean(p.product_slot_id),
    current_machine_qty: newQty,
    last_stock_update_source: 'WF6_NACHFUELLUNG',
    last_stock_update_at: now
  };
});

// Hinweise die aufgelÃ¶st werden sollen
const resolvableTypes = ['EMPTY_BATCH', 'LOW_STOCK', 'INSUFFICIENT_BATCH_STOCK', 'LOW_BATCH'];
const toResolve = allHinweise.filter(h => {
  const resolved = clean(h.resolved).toUpperCase();
  if (['TRUE','JA','YES','1','ERLEDIGT','RESOLVED'].includes(resolved)) return false;
  return clean(h.product_key) === productKey && resolvableTypes.includes(clean(h.type));
}).map(h => ({ created_at: clean(h.created_at), resolved: 'TRUE' }));

// Audit-Eintrag
const auditEntry = {
  created_at: now,
  type: 'NACHFUELLUNG',
  severity: 'info',
  machine_id: clean(matchedSlots[0].machine_id || '457107528'),
  product_key: productKey,
  nayax_product_name: productName,
  message: 'NachfÃ¼llung erfasst fÃ¼r ' + productName +
           '. Slots aktualisiert: ' + slotUpdates.map(s => s.product_slot_id + '=' + s.current_machine_qty).join(', ') +
           (notesIn ? '. Bemerkung: ' + notesIn : ''),
  resolved: 'TRUE'
};

return [{
  json: {
    ok: true,
    productKey,
    productName,
    slotUpdates,
    toResolve,
    auditEntry,
    summary: {
      slots_updated: slotUpdates.length,
      hints_resolved: toResolve.length
    }
  }
}];

const d = $input.first().json;
const updates = d.slotUpdates || [];
if (!updates.length) return [];
return updates.map(u => ({ json: u }));

const d = $input.first().json;
const hints = d.toResolve || [];
if (!hints.length) return [];
return hints.map(h => ({ json: h }));

const result = $("Code - Nachfuellung verarbeiten").first().json;
const products = $("Google Sheets - Produkte lesen").all().map((item) => item.json);
const batches = $("Google Sheets - Lagerchargen lesen").all().map((item) => item.json);
const batchRunId = "wf7_" + new Date().toISOString().slice(0, 10);

function clean(value) {
  return String(value ?? "").replace(/\n/g, " ").replace(/\s+/g, " ").trim();
}

function num(value) {
  const n = Number(String(value ?? "").replace(",", "."));
  return Number.isFinite(n) ? n : null;
}

function isActive(value) {
  return ["TRUE", "1", "JA", "YES", "AKTIV", "ACTIVE", ""].includes(clean(value).toUpperCase());
}

function sanitize(value) {
  return clean(value).toUpperCase().replace(/[^A-Z0-9]+/g, "_").replace(/^_+|_+$/g, "");
}

function batchFor(productKey) {
  return batches
    .filter((batch) => clean(batch.product_key) === productKey)
    .filter((batch) => isActive(batch.status))
    .filter((batch) => (num(batch.remaining_qty) ?? 0) > 0)
    .sort((a, b) => clean(a.mhd).localeCompare(clean(b.mhd)) || clean(a.batch_id).localeCompare(clean(b.batch_id)))[0];
}

return (result.slotUpdates || []).flatMap((update) => {
  const slot = products.find((product) => clean(product.product_slot_id) === clean(update.product_slot_id));
  if (!slot) return [];
  const delta = (num(update.current_machine_qty) ?? 0) - (num(slot.current_machine_qty) ?? 0);
  if (delta <= 0) return [];
  const batch = batchFor(clean(slot.product_key));
  if (!batch) return [];
  const movementKey = ["MOV", "REFILL", update.product_slot_id, batch.batch_id, new Date().toISOString().slice(0, 10), delta].map(sanitize).join("_");
  return [{
    json: {
      event_type: "stock_movement",
      batch_run_id: batchRunId,
      data: {
        movement_key: movementKey,
        batch_key: clean(batch.batch_id),
        product_slot_key: clean(update.product_slot_id),
        movement_type: "refill",
        quantity_delta_total: 0,
        quantity_delta_slot: delta,
        reason: clean(result.auditEntry?.message || "Nachfuellung erfasst"),
        source: "wf7_nachfuellung",
        occurred_at: clean(update.last_stock_update_at) || new Date().toISOString(),
      },
    },
  }];
});
